	/*@mixed@*//*C mixed C*/ function RetrievePref(/**< string username*/ $username, /**< string preferenceName */ $preferenceName)
	{
		/*Retrieve the value of a user preference*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: system*/
		/*	Use Case When: looking up a user preference*/
		/*	Use Case What: return the preference if set*/
		/*	Use Case Why: so that default values can be user specific*/
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		require_once('security/users.class.php' );
		$users = new users();
		require_once( MODELDIR . '/userpref_tlv.class.php' );
		$userpref_tlv = new userpref_tlv();
		
		$userpref_tlv->Setpref( $preferenceName );
		$userpref_tlv->GetVARRow();
		$this->Setiduserpref_tlv( $userpref_tlv->Getiduserpref_tlv() );
		$users->Setusername( $username );
		$users->GetVARRow();
		$this->Setidusers( $users->Getidusers() );
		$this->GetVARRow();
		
		if( isset( $this->value ))
		{
			return $this->value;
		}
		else
			return NULL;
		//If we don't have a return in the body in codemeta, return
		return NULL;
	}
